sql:
SELECT ant_id, MAX(calibration_date) AS latest_calibration_date
FROM antennas
GROUP BY ant_id;

SELECT AVG(data_value) AS average_data_value
  FROM collected_data
  WHERE ant_id = 0 AND sensor_id = 0;
